 26→	async findById({
 27→		companyId,
 28→	}: {
 29→		companyId: ICompanyBase['_id'];
 30→	}): Promise<ICompanyBase | null> {
 31→		try {
 32→			const result = await this.knexRead<ICompanyBase>(this.tableName)
 33→				.where({ _id: companyId })
 34→				.whereNull('deleted_at')
 35→				.first();
 36→
 37→			if (!result) {
 38→				return null;
 39→			}
 40→
 41→			const dto = plainToInstance(CompanyBaseDto, result);
 42→			const errors = await validate(dto, { skipMissingProperties: true });
 43→			if (errors.length > 0) {
 44→				this.logger.error(
 45→					`Validation failed for company data: ${this.formatValidationErrors({ errors })}`,
 46→				);
 47→				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
 48→			}
 49→
 50→			return result;
 51→		} catch (error) {
 52→			this.logger.error(
 53→				`Failed to find company by id ${companyId}: ${(error as Error).message}`,
 54→			);
 55→			throw error;
 56→		}
 57→	}
 58→
 59→	async create({ data }: { data: ICompanyCreate }): Promise<ICompanyBase> {
 60→		try {
 61→			const dto = plainToInstance(CompanyBaseDto, data);
 62→			const errors = await validate(dto, { skipMissingProperties: true });
 63→			if (errors.length > 0) {
 64→				this.logger.error(
 65→					`Validation failed for company data: ${this.formatValidationErrors({ errors })}`,
 66→				);
 67→				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
 68→			}
 69→
 70→			const _id = randomUUID();
 71→			const [created] = await this.knexWrite<ICompanyBase>(this.tableName)
 72→				.insert({
 73→					_id,
 74→					...data,
 75→					created_at: this.knexWrite.fn.now(),
 76→					updated_at: this.knexWrite.fn.now(),
 77→				})
 78→				.returning('*');
 79→
 80→			if (!created) {
 81→				throw new Error('Failed to create company');
 82→			}
 83→
 84→			this.logger.debug(`Created company with id ${_id}`);
 85→			return created;
 86→		} catch (error) {
 87→			this.logger.error(`Failed to create company: ${(error as Error).message}`);
 88→			throw error;
 89→		}
 90→	}
