 92→	async softDelete({ companyId }: { companyId: ICompanyBase['_id'] }): Promise<void> {
 93→		try {
 94→			await this.knexWrite<ICompanyBase>(this.tableName)
 95→				.where({ _id: companyId })
 96→				.whereNull('deleted_at')
 97→				.update({
 98→					deleted_at: this.knexWrite.fn.now(),
 99→					updated_at: this.knexWrite.fn.now(),
100→				});
101→
102→			this.logger.debug(`Soft deleted company ${companyId}`);
103→		} catch (error) {
104→			this.logger.error(
105→				`Failed to soft delete company ${companyId}: ${(error as Error).message}`,
106→			);
107→			throw error;
108→		}
109→	}
