 11→import { IOAuthAccountBase } from '@modules/oauth-account/types/oauth-account.base.interface';
 12→import { IOAuthAccountCreate } from '@modules/oauth-account/types/oauth-account.create.interface';
 13→
 14→import { TABLE_NAME_OAUTH_ACCOUNTS } from '@constants/db.constant';
 15→import { ENCRYPTION_KEY } from '@constants/env-variables.constant';
 16→import { decrypt, encrypt } from '@utils/encryption.util';
 17→import { getEnv } from '@utils/get-env-variable.util';
 18→
 19→@Injectable()
 20→export class OAuthAccountModel {
 21→	private readonly logger = new Logger(OAuthAccountModel.name);
 22→	private readonly tableName = TABLE_NAME_OAUTH_ACCOUNTS;
 23→
 24→	constructor(
 25→		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
 26→		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
 27→	) {}
 28→
 29→	private getEncryptionKey(): string {
 30→		return getEnv<string>({ key: ENCRYPTION_KEY });
 31→	}
 32→
 33→	private decryptToken({ row }: { row: IOAuthAccountBase }): IOAuthAccountBase {
 34→		if (row.access_token === null) {
 35→			return row;
 36→		}
 37→		const key = this.getEncryptionKey();
 38→		return { ...row, access_token: decrypt({ ciphertext: row.access_token, key }) };
 39→	}
 40→
 41→	private formatValidationErrors({ errors }: { errors: ValidationError[] }): string {
 42→		return errors
 43→			.map(
 44→				(error) =>
 45→					`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
 46→			)
 47→			.join('; ');
 48→	}
 49→
 50→	async findByProviderAndProviderId({
 51→		provider,
 52→		providerId,
 53→	}: {
 54→		provider: IOAuthAccountBase['provider'];
 55→		providerId: IOAuthAccountBase['provider_id'];
 56→	}): Promise<IOAuthAccountBase | null> {
 57→		try {
 58→			const result = await this.knexRead<IOAuthAccountBase>(this.tableName)
 59→				.where({ provider, provider_id: providerId })
 60→				.whereNull('deleted_at')
 61→				.first();
 62→
 63→			if (!result) {
 64→				return null;
 65→			}
 66→
 67→			const dto = plainToInstance(OAuthAccountBaseDto, result);
 68→			const errors = await validate(dto, { skipMissingProperties: true });
 69→			if (errors.length > 0) {
 70→				this.logger.error(
 71→					`Validation failed for oauth account data: ${this.formatValidationErrors({ errors })}`,
 72→				);
 73→				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
 74→			}
 75→
 76→			return this.decryptToken({ row: result });
 77→		} catch (error) {
 78→			this.logger.error(
 79→				`Failed to find oauth account by provider ${provider} and providerId ${providerId}: ${(error as Error).message}`,
 80→			);
 81→			throw error;
 82→		}
 83→	}
 84→
 85→	async findByUserId({
 86→		userId,
 87→	}: {
 88→		userId: IOAuthAccountBase['user_id'];
 89→	}): Promise<IOAuthAccountBase[]> {
 90→		try {
 91→			const results = await this.knexRead<IOAuthAccountBase>(this.tableName)
 92→				.where({ user_id: userId })
 93→				.whereNull('deleted_at');
 94→
 95→			return results.map((row) => this.decryptToken({ row }));
 96→		} catch (error) {
 97→			this.logger.error(
 98→				`Failed to find oauth accounts for user ${userId}: ${(error as Error).message}`,
 99→			);
100→			throw error;
101→		}
102→	}
103→
104→	async findByEmail({
105→		email,
106→	}: {
107→		email: IOAuthAccountBase['email'];
108→	}): Promise<IOAuthAccountBase[]> {
109→		try {
110→			const results = await this.knexRead<IOAuthAccountBase>(this.tableName)
111→				.where({ email })
112→				.whereNull('deleted_at');
113→
114→			return results.map((row) => this.decryptToken({ row }));
115→		} catch (error) {
116→			this.logger.error(
117→				`Failed to find oauth accounts by email ${email}: ${(error as Error).message}`,
118→			);
119→			throw error;
120→		}
121→	}
122→
123→	async create({ data }: { data: IOAuthAccountCreate }): Promise<IOAuthAccountBase> {
124→		try {
125→			const dto = plainToInstance(OAuthAccountBaseDto, data);
126→			const errors = await validate(dto, { skipMissingProperties: true });
127→			if (errors.length > 0) {
128→				this.logger.error(
129→					`Validation failed for oauth account data: ${this.formatValidationErrors({ errors })}`,
130→				);
131→				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
132→			}
133→
134→			const key = this.getEncryptionKey();
135→			const encryptedToken =
136→				data.access_token !== null && data.access_token !== undefined
137→					? encrypt({ plaintext: data.access_token, key })
138→					: null;
139→
140→			const _id = randomUUID();
141→			const [created] = await this.knexWrite<IOAuthAccountBase>(this.tableName)
142→				.insert({
143→					_id,
144→					...data,
145→					access_token: encryptedToken,
146→					created_at: this.knexWrite.fn.now(),
147→					updated_at: this.knexWrite.fn.now(),
148→				})
149→				.returning('*');
150→
151→			if (!created) {
152→				throw new Error('Failed to create oauth account');
153→			}
154→
155→			this.logger.debug(`Created oauth account with id ${_id}`);
156→			return this.decryptToken({ row: created });
157→		} catch (error) {
158→			this.logger.error(`Failed to create oauth account: ${(error as Error).message}`);
