export interface ICompanyMemberBase {
	_id: string;
	user_id: string;
	company_id: string;
	role: 'admin' | 'member';
	created_at: Date;
	updated_at: Date;
	deleted_at: Date | null;
}

import type { ICompanyMemberBase } from '@modules/company-member/types/company-member.base.interface';

export type ICompanyMemberCreate = Omit<
	ICompanyMemberBase,
	'_id' | 'created_at' | 'updated_at' | 'deleted_at'
>;

import { IsDate, IsIn, IsNotEmpty, IsOptional, IsString, IsUUID } from 'class-validator';

export class CompanyMemberBaseDto {
	@IsUUID()
	@IsNotEmpty()
	_id: string;

	@IsUUID()
	@IsNotEmpty()
	user_id: string;

	@IsUUID()
	@IsNotEmpty()
	company_id: string;

	@IsIn(['admin', 'member'])
	@IsNotEmpty()
	role: 'admin' | 'member';

	@IsDate()
	@IsNotEmpty()
	created_at: Date;

	@IsDate()
	@IsNotEmpty()
	updated_at: Date;

	@IsOptional()
	@IsDate()
	deleted_at: Date | null;
}

import { OmitType } from '@nestjs/swagger';

import { CompanyMemberBaseDto } from '@modules/company-member/dto/company-member.base.dto';

export class CompanyMemberCreateDto extends OmitType(CompanyMemberBaseDto, [
	'_id',
	'created_at',
	'updated_at',
	'deleted_at',
] as const) {}

