import { randomUUID } from 'node:crypto';

import { Injectable, Logger } from '@nestjs/common';
import { plainToInstance } from 'class-transformer';
import { validate, ValidationError } from 'class-validator';
import { Knex } from 'knex';
import { InjectConnection } from 'nest-knexjs';

import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';
import { CompanyMemberBaseDto } from '@modules/company-member/dto/company-member.base.dto';
import { ICompanyMemberBase } from '@modules/company-member/types/company-member.base.interface';
import { ICompanyMemberCreate } from '@modules/company-member/types/company-member.create.interface';

import { TABLE_NAME_COMPANY_MEMBERS } from '@constants/db.constant';

@Injectable()
export class CompanyMemberModel {
	private readonly logger = new Logger(CompanyMemberModel.name);
	private readonly tableName = TABLE_NAME_COMPANY_MEMBERS;

	constructor(
		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
	) {}

	async findByUserAndCompany({
		userId,
		companyId,
	}: {
		userId: ICompanyMemberBase['user_id'];
		companyId: ICompanyMemberBase['company_id'];
	}): Promise<ICompanyMemberBase | null> {
		try {
			const result = await this.knexRead<ICompanyMemberBase>(this.tableName)
				.where({ user_id: userId, company_id: companyId })
				.whereNull('deleted_at')
				.first();

			if (!result) {
				return null;
			}

			const dto = plainToInstance(CompanyMemberBaseDto, result);
			const errors = await validate(dto, { skipMissingProperties: true });
			if (errors.length > 0) {
				this.logger.error(
					`Validation failed for company member data: ${this.formatValidationErrors({ errors })}`,
				);
				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
			}

			return result;
		} catch (error) {
			this.logger.error(
				`Failed to find company member by user ${userId} and company ${companyId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async findByUserId({
		userId,
	}: {
		userId: ICompanyMemberBase['user_id'];
	}): Promise<ICompanyMemberBase[]> {
		try {
			const results = await this.knexRead<ICompanyMemberBase>(this.tableName)
				.where({ user_id: userId })
				.whereNull('deleted_at');

			return results;
		} catch (error) {
			this.logger.error(
				`Failed to find company memberships for user ${userId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async findByCompanyId({
		companyId,
	}: {
		companyId: ICompanyMemberBase['company_id'];
	}): Promise<ICompanyMemberBase[]> {
		try {
			const results = await this.knexRead<ICompanyMemberBase>(this.tableName)
				.where({ company_id: companyId })
				.whereNull('deleted_at');

			return results;
		} catch (error) {
			this.logger.error(
				`Failed to find members for company ${companyId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async findAdminByCompanyId({
		companyId,
	}: {
		companyId: ICompanyMemberBase['company_id'];
	}): Promise<ICompanyMemberBase | null> {
		try {
			const result = await this.knexRead<ICompanyMemberBase>(this.tableName)
				.where({ company_id: companyId, role: 'admin' })
				.whereNull('deleted_at')
				.first();

			if (!result) {
				return null;
			}

			const dto = plainToInstance(CompanyMemberBaseDto, result);
			const errors = await validate(dto, { skipMissingProperties: true });
			if (errors.length > 0) {
				this.logger.error(
					`Validation failed for company member data: ${this.formatValidationErrors({ errors })}`,
				);
				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
			}

			return result;
		} catch (error) {
			this.logger.error(
				`Failed to find admin for company ${companyId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async create({ data }: { data: ICompanyMemberCreate }): Promise<ICompanyMemberBase> {
		try {
			const dto = plainToInstance(CompanyMemberBaseDto, data);
			const errors = await validate(dto, { skipMissingProperties: true });
			if (errors.length > 0) {
				this.logger.error(
					`Validation failed for company member data: ${this.formatValidationErrors({ errors })}`,
				);
				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
			}

			const _id = randomUUID();
			const [created] = await this.knexWrite<ICompanyMemberBase>(this.tableName)
				.insert({
					_id,
					...data,
					created_at: this.knexWrite.fn.now(),
					updated_at: this.knexWrite.fn.now(),
				})
				.returning('*');

			if (!created) {
				throw new Error('Failed to create company member');
			}

			this.logger.debug(`Created company member with id ${_id}`);
			return created;
		} catch (error) {
			this.logger.error(`Failed to create company member: ${(error as Error).message}`);
			throw error;
		}
	}

	async softDelete({
		companyMemberId,
	}: {
		companyMemberId: ICompanyMemberBase['_id'];
	}): Promise<void> {
		try {
			await this.knexWrite<ICompanyMemberBase>(this.tableName)
				.where({ _id: companyMemberId })
				.whereNull('deleted_at')
				.update({
					deleted_at: this.knexWrite.fn.now(),
					updated_at: this.knexWrite.fn.now(),
				});

			this.logger.debug(`Soft deleted company member ${companyMemberId}`);
		} catch (error) {
			this.logger.error(
				`Failed to soft delete company member ${companyMemberId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async createWithTransaction({
		trx,
		data,
	}: {
		trx: Knex.Transaction;
		data: ICompanyMemberCreate;
	}): Promise<ICompanyMemberBase> {
		try {
			const dto = plainToInstance(CompanyMemberBaseDto, data);
			const errors = await validate(dto, { skipMissingProperties: true });
			if (errors.length > 0) {
				this.logger.error(
					`Validation failed for company member data: ${this.formatValidationErrors({ errors })}`,
				);
				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
			}

			const _id = randomUUID();
			const [created] = await trx<ICompanyMemberBase>(this.tableName)
				.insert({
					_id,
					...data,
					created_at: trx.fn.now(),
					updated_at: trx.fn.now(),
				})
				.returning('*');

			if (!created) {
				throw new Error('Failed to create company member');
			}

			this.logger.debug(`Created company member with id ${_id} in transaction`);
			return created;
		} catch (error) {
			this.logger.error(
				`Failed to create company member in transaction: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async softDeleteByUserAndCompany({
		userId,
		companyId,
	}: {
		userId: ICompanyMemberBase['user_id'];
		companyId: ICompanyMemberBase['company_id'];
	}): Promise<void> {
		try {
			await this.knexWrite<ICompanyMemberBase>(this.tableName)
				.where({ user_id: userId, company_id: companyId })
				.whereNull('deleted_at')
				.update({
					deleted_at: this.knexWrite.fn.now(),
					updated_at: this.knexWrite.fn.now(),
				});

			this.logger.debug(
				`Soft deleted company member for user ${userId} in company ${companyId}`,
			);
		} catch (error) {
			this.logger.error(
				`Failed to soft delete company member for user ${userId} in company ${companyId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	private formatValidationErrors({ errors }: { errors: ValidationError[] }): string {
		return errors
			.map(
				(error) =>
					`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
			)
			.join('; ');
	}
}

